import{c as s,Q as t,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Investor vs issuer","description":"One passkey, one role. How to tell them apart and use both.","frontmatter":{"title":"Investor vs issuer","description":"One passkey, one role. How to tell them apart and use both."},"headers":[],"relativePath":"get-started/investor-vs-issuer.md","filePath":"get-started/investor-vs-issuer.md","lastUpdated":1780196777000}'),i={name:"get-started/investor-vs-issuer.md"};function r(n,e,l,d,u,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="investor-vs-issuer" tabindex="-1">Investor vs issuer <a class="header-anchor" href="#investor-vs-issuer" aria-label="Permalink to &quot;Investor vs issuer&quot;">​</a></h1><p>MuHaven has <strong>two distinct roles</strong>: investor (you hold encrypted RWA balances and pull yield) and issuer (you create tokens, fund yield epochs, and manage the KYC whitelist). The agentic surfaces honor that split — the issuer tools (<code>muhaven_propose_distribute_yield</code>, <code>muhaven_propose_kyc_add</code>, etc.) only appear when you&#39;re signed in as an approved issuer.</p><h2 id="the-rule-one-passkey-one-role" tabindex="-1">The rule: one passkey, one role <a class="header-anchor" href="#the-rule-one-passkey-one-role" aria-label="Permalink to &quot;The rule: one passkey, one role&quot;">​</a></h2><p>A given passkey-bound MuHaven wallet can be <strong>either</strong> an investor <strong>or</strong> an issuer — never both, by design. Crossing roles after the fact is rejected at the backend (<code>403 ROLE_MISMATCH</code> for cross-role login; <code>403 HAS_INVESTOR_ACTIVITY</code> if you try to issuer-onboard a wallet that already invested).</p><p>If you plan to operate both sides:</p><ol><li>Register <strong>one passkey</strong> for your investor account.</li><li>Register <strong>a second passkey</strong> (different name, ideally on a different device or sub-vault in your password manager) for your issuer account.</li><li>Sign in with the appropriate passkey for whichever role you need that session.</li></ol><div class="warning custom-block"><p class="custom-block-title">Why so strict?</p><p>Issuers see aggregate KYC whitelist state and can write to it; investors see encrypted personal balances and the yield-claim path. Keeping the MuHaven wallets separate prevents accidental privilege escalation and keeps the audit log unambiguous about which on-chain identity took which action.</p></div><h2 id="what-an-investor-can-do" tabindex="-1">What an investor can do <a class="header-anchor" href="#what-an-investor-can-do" aria-label="Permalink to &quot;What an investor can do&quot;">​</a></h2><ul><li>Hold encrypted RWA tokens (one or more, picked from the active catalog).</li><li>Buy / redeem via the Subscription surface.</li><li>Claim yield from finalized epochs.</li><li>Set tier / pause / inspect the audit log.</li><li>Vote (encrypted ballot) in governance proposals.</li><li>See public protection-pool state for any RWA token.</li></ul><h2 id="what-an-issuer-can-do" tabindex="-1">What an issuer can do <a class="header-anchor" href="#what-an-issuer-can-do" aria-label="Permalink to &quot;What an issuer can do&quot;">​</a></h2><ul><li>Create RWA tokens (today: wrapped via <code>MuHavenVault</code>; native issuance planned for a later release).</li><li>Schedule yield epochs (<code>SDK.distributeYield → startDistribution → batchCreate → fundFrom</code>).</li><li>Add / remove investor wallets from the ERC-3643 KYC whitelist.</li><li>Unpause a freshly-deployed token (set NAV + flip <code>paused=false</code>).</li><li>Query the issuer-side audit log.</li><li>Mint <strong>hosted-checkout links</strong> to sell to non-customer buyers.</li><li>See aggregate token state (total supply <em>handle</em>, holder count) — never per-investor balances.</li></ul><h2 id="how-the-role-check-works-under-the-hood" tabindex="-1">How the role check works under the hood <a class="header-anchor" href="#how-the-role-check-works-under-the-hood" aria-label="Permalink to &quot;How the role check works under the hood&quot;">​</a></h2><p>Every backend route that gates on role uses a <code>withRole(&#39;issuer&#39; | &#39;investor&#39;)</code> middleware:</p><ul><li>Your JWT carries a <code>role</code> claim populated at sign-in based on the wallet&#39;s registered role.</li><li>If the route says <code>withRole(&#39;issuer&#39;)</code> and your JWT claims <code>&#39;investor&#39;</code>, you get <strong>403 NOT_APPROVED_ISSUER</strong>.</li><li>Issuers also pass a separate <code>issuerStatus === &#39;approved&#39;</code> check on every state-mutating tool. Pending or suspended issuers see issuer tools but get <strong>403 NOT_APPROVED_ISSUER</strong> when they try to invoke them.</li></ul><p>The same check applies in every surface:</p><ul><li>HavenBot hides issuer tools from investor passkeys.</li><li><code>@muhaven/mcp</code> advertises issuer tools but the backend rejects investor JWTs at the route boundary.</li><li>OpenClaw skill subset <em>excludes</em> the issuer namespace entirely (Telegram is investor-only).</li><li>Hosted Checkout&#39;s create-link tool is gated on <code>issuerStatus === &#39;approved&#39;</code>.</li></ul><h2 id="end-to-end-walkthroughs-need-two-passkeys" tabindex="-1">End-to-end walkthroughs need two passkeys <a class="header-anchor" href="#end-to-end-walkthroughs-need-two-passkeys" aria-label="Permalink to &quot;End-to-end walkthroughs need two passkeys&quot;">​</a></h2><p>If you&#39;re recording a demo or doing a manual end-to-end test that exercises both an issuer flow (e.g., distribute yield) and an investor flow (e.g., claim that yield), you need <strong>two passkeys</strong>:</p><ol><li>Sign in as the issuer, kick off <code>muhaven_propose_distribute_yield</code>, sign with the issuer passkey.</li><li>Sign out.</li><li>Sign in as an investor with a balance in that token, call <code>muhaven_propose_claim</code>, sign with the investor passkey.</li></ol><p>Trying to do both with one passkey will fail the role check. Don&#39;t.</p><h2 id="switching-between-passkeys-in-your-password-manager" tabindex="-1">Switching between passkeys in your password manager <a class="header-anchor" href="#switching-between-passkeys-in-your-password-manager" aria-label="Permalink to &quot;Switching between passkeys in your password manager&quot;">​</a></h2><p>Most password managers (1Password, Bitwarden, iCloud Keychain) let you give each passkey a recognizable name at creation:</p><ul><li><strong>MuHaven — Investor (Personal)</strong></li><li><strong>MuHaven — Issuer (Treasury)</strong></li></ul><p>At sign-in, the OS dialog will list them by name so you can pick the right one quickly.</p><h2 id="i-want-to-become-an-issuer-but-i-have-investor-activity" tabindex="-1">I want to <em>become</em> an issuer, but I have investor activity <a class="header-anchor" href="#i-want-to-become-an-issuer-but-i-have-investor-activity" aria-label="Permalink to &quot;I want to *become* an issuer, but I have investor activity&quot;">​</a></h2><p>You can&#39;t promote a MuHaven wallet that already invested. The cleanest path: <strong>register a new passkey</strong> and apply-issuer with that one. Your investor MuHaven wallet keeps its balances; the new wallet operates as a separate issuer identity.</p><p>The reverse (issuer wants to become an investor) has the same shape — cleanest path is a fresh passkey.</p><h2 id="how-to-apply-as-an-issuer" tabindex="-1">How to apply as an issuer <a class="header-anchor" href="#how-to-apply-as-an-issuer" aria-label="Permalink to &quot;How to apply as an issuer&quot;">​</a></h2><p>Sign in with the passkey you want to use as the issuer, then go to <code>/apply-issuer</code>. The flow is:</p><ol><li>Connect your KYB info (legal entity name, jurisdiction).</li><li>Pick the token symbol you intend to issue.</li><li>Wait for approval (today: auto-approved in dev mode; production: manual review until <code>disableDevModeForever()</code> is called).</li></ol><p>After approval, issuer tools become visible across all four surfaces.</p>',31)])])}const y=s(i,[["render",r]]);export{p as __pageData,y as default};
